async function readStdinAsync(stdin) {
  if (stdin === null) return null;
  if (stdin instanceof Uint8Array) return stdin;
  const chunks = [];
  for await (const chunk of stdin) chunks.push(chunk);
  return concat3(chunks);
}
async function* wrapBytes(data) {
  yield data;
}
function resolveSource(stdin, errorMsg) {
  if (stdin === null) throw new Error(errorMsg);
  if (stdin instanceof Uint8Array) return wrapBytes(stdin);
  return stdin;
}
function concat3(chunks) {
  let total = 0;
  for (const c of chunks) total += c.byteLength;
  const out = new Uint8Array(total);
  let offset = 0;
  for (const c of chunks) {
    out.set(c, offset);
    offset += c.byteLength;
  }
  return out;
}

